tlPhysicsVectorChunk&
tlPhysicsVectorChunk::operator=(const tlPhysicsVectorChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    x = a.x;
    y = a.y;
    z = a.z;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlPhysicsVectorChunk::operator==(const tlDataChunk& a)
{

    const tlPhysicsVectorChunk* aptr = dynamic_cast<const tlPhysicsVectorChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(x == aptr->x))
    {
        return false;
    }
    if(!(y == aptr->y))
    {
        return false;
    }
    if(!(z == aptr->z))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

